import React, { useMemo, useState, useEffect, useCallback } from 'react';
import { useTable, useSortBy, usePagination } from 'react-table';
import './PurchaseFunc.css';

const Stocks = ({ apiBaseUrl }) => {
  const [materials, setMaterials] = useState([]);
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [outflows, setOutflows] = useState([]);
  const [selectedLocation, setSelectedLocation] = useState('');
  const [globalFilterOne, setGlobalFilterOne] = useState('');
  const [globalFilterTwo, setGlobalFilterTwo] = useState('');

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${authToken}`,
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [materialResponse, purchaseResponse, locationResponse, outflowsResponse] = await Promise.all([
          fetchAPI(`${apiBaseUrl}/materiallist`),
          fetchAPI(`${apiBaseUrl}/PurchasesAPI`),
          fetchAPI(`${apiBaseUrl}/LocationsAPI`),
          fetchAPI(`${apiBaseUrl}/outflowsAPI`),
        ]);
        setMaterials(materialResponse);
        setPurchases(purchaseResponse);
        setLocations(locationResponse);
        setOutflows(outflowsResponse);
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
    fetchData();
  }, [apiBaseUrl, fetchAPI]);

  const filteredData = useMemo(() => {
    return purchases.filter((row) => {
      const material = materials.find((m) => m.matid === row.materialid);
      const materialName = material ? material.name.toLowerCase() : '';
      const rowString =
        Object.values(row)
          .map((val) => String(val).toLowerCase())
          .join(' ') + ' ' + materialName;

      return (
        rowString.includes(globalFilterOne.toLowerCase()) &&
        rowString.includes(globalFilterTwo.toLowerCase())
      );
    });
  }, [purchases, globalFilterOne, globalFilterTwo, materials]);

  const calculateTotalCost = (row) => {
    const materialId = row.materialid;
    const lotNumber = row.lotnumber;
    const location = row.location;

    const filteredPurchases = purchases.filter(
      (purchase) =>
        purchase.materialid === materialId &&
        purchase.lotnumber === lotNumber &&
        purchase.location === location
    );

    const filteredOutflows = outflows.filter(
      (outflow) =>
        outflow.materialid === materialId &&
        outflow.lotnumber === lotNumber &&
        outflow.location === location
    );

    const totalPurchases = filteredPurchases.reduce((sum, purchase) => sum + purchase.quantity * purchase.price, 0);
    const totalOutflows = filteredOutflows.reduce((sum, outflow) => sum + outflow.quantity * outflow.price, 0);

    return totalPurchases - totalOutflows;
  };

  const totalStockCost = useMemo(() => {
    return filteredData.reduce((sum, row) => sum + calculateTotalCost(row), 0);
  }, [filteredData,calculateTotalCost]);

  const columns = useMemo(
    () => [
      { Header: 'Material ID', accessor: 'materialid' },
      {
        Header: 'Material Name',
        accessor: (row) => {
          const material = materials.find((m) => m.matid === row.materialid);
          return material ? material.name : 'Material not found';
        },
      },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Quantity', accessor: 'quantity' },
      {
        Header: 'Material Field',
        accessor: (row) => {
          const material = materials.find((m) => m.matid === row.materialid);
          return material ? material.field : 'Field not available';
        },
      },
    ],
    [materials]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
  } = useTable(
    {
      columns,
      data: filteredData,
      initialState: { pageIndex: 0, pageSize: 10 },
    },
    useSortBy,
    usePagination
  );

  return (
    <div className="container">
      <div className="form-group">
        <label>Location:</label>
        <select
          name="location"
          value={selectedLocation}
          onChange={(e) => setSelectedLocation(e.target.value)}
          required
        >
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>

      <div className="search">
        <input
          value={globalFilterOne}
          onChange={(e) => setGlobalFilterOne(e.target.value)}
          placeholder="Global Filter 1"
        />
        <input
          value={globalFilterTwo}
          onChange={(e) => setGlobalFilterTwo(e.target.value)}
          placeholder="Global Filter 2"
        />
      </div>

      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>
                    {column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}
                  </span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>

      <div className="pagination">
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page {pageIndex + 1} of {Math.ceil(filteredData.length / pageSize)}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => gotoPage(Number(e.target.value) - 1)}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => setPageSize(Number(e.target.value))}
        >
          {[10, 25, 50].map((size) => (
            <option key={size} value={size}>
              Show {size}
            </option>
          ))}
        </select>
      </div>

      <div className="total-cost">
        <strong>Total Stock Cost:</strong> {totalStockCost.toFixed(2)} €
      </div>
    </div>
  );
};

export default Stocks;
